#!/usr/bin/env bash
# post-review.sh
# Parses the pipeline JSON output and posts a bundled GitHub review.
#
# Required env vars: GH_TOKEN, PR_NUMBER, REPO, PIPELINE_OUTCOME

set -uo pipefail

OUTPUT_FILE="pipeline-output.json"

# ---------------------------------------------------------------------------
# Retry helper — exponential backoff (3 attempts: 2s, 4s, 8s)
# ---------------------------------------------------------------------------
retry() {
  local max_attempts=3
  local delay=2
  local attempt=1
  while true; do
    if "$@"; then
      return 0
    fi
    if (( attempt >= max_attempts )); then
      echo "::error::Command failed after ${max_attempts} attempts: $*"
      return 1
    fi
    echo "  Retry ${attempt}/${max_attempts} in ${delay}s..."
    sleep "$delay"
    delay=$(( delay * 2 ))
    attempt=$(( attempt + 1 ))
  done
}

# ---------------------------------------------------------------------------
# 1. Handle pipeline crash (no output produced)
# ---------------------------------------------------------------------------
if [[ "$PIPELINE_OUTCOME" == "failure" ]] && [[ ! -f "$OUTPUT_FILE" ]]; then
  echo "Pipeline crashed without producing output. Posting error review..."
  retry gh api "repos/${REPO}/pulls/${PR_NUMBER}/reviews" \
    --method POST \
    --field event="REQUEST_CHANGES" \
    --field body="<!-- pr-code-review-validator -->
## REVIEW ERROR — pipeline failed

The review pipeline encountered an error and could not complete.
This blocks merging as a safety measure (fail-closed policy).

Please re-run the workflow or check the [Actions logs](https://github.com/${REPO}/actions) for details.

---
*This review was generated by the PR Code Review Validator.*" \
    --field commit_id="$(git rev-parse HEAD)"
  exit 1
fi

# Handle case where output file doesn't exist for other reasons
if [[ ! -f "$OUTPUT_FILE" ]]; then
  echo "::error::Pipeline output file not found and outcome was: ${PIPELINE_OUTCOME}"
  retry gh api "repos/${REPO}/pulls/${PR_NUMBER}/reviews" \
    --method POST \
    --field event="REQUEST_CHANGES" \
    --field body="<!-- pr-code-review-validator -->
## REVIEW ERROR — no output

The review pipeline did not produce an output file (outcome: ${PIPELINE_OUTCOME}).
This blocks merging as a safety measure (fail-closed policy).

Please re-run the workflow or check the [Actions logs](https://github.com/${REPO}/actions) for details.

---
*This review was generated by the PR Code Review Validator.*" \
    --field commit_id="$(git rev-parse HEAD)"
  exit 1
fi

# ---------------------------------------------------------------------------
# 2. Validate and parse pipeline output
# ---------------------------------------------------------------------------
if ! jq empty "$OUTPUT_FILE" 2>/dev/null; then
  echo "::error::Pipeline output is not valid JSON"
  retry gh api "repos/${REPO}/pulls/${PR_NUMBER}/reviews" \
    --method POST \
    --field event="REQUEST_CHANGES" \
    --field body="<!-- pr-code-review-validator -->
## REVIEW ERROR — invalid pipeline output

The review pipeline produced output that could not be parsed as JSON.
This blocks merging as a safety measure (fail-closed policy).

Please re-run the workflow or check the [Actions logs](https://github.com/${REPO}/actions) for details.

---
*This review was generated by the PR Code Review Validator.*" \
    --field commit_id="$(git rev-parse HEAD)"
  exit 1
fi

VERDICT=$(jq -r '.verdict' "$OUTPUT_FILE")
SUMMARY=$(jq -r '.summary' "$OUTPUT_FILE")
NUM_COMMENTS=$(jq '.inline_comments | length' "$OUTPUT_FILE")

echo "Verdict: ${VERDICT}"
echo "Inline comments: ${NUM_COMMENTS}"

# ---------------------------------------------------------------------------
# 3. Determine review event and exit code
# ---------------------------------------------------------------------------
case "$VERDICT" in
  "fail")
    EVENT="REQUEST_CHANGES"
    EXIT_CODE=1
    ;;
  "pass"|"skip")
    EVENT="COMMENT"
    EXIT_CODE=0
    ;;
  *)
    echo "::error::Unknown verdict: ${VERDICT}"
    exit 1
    ;;
esac

# ---------------------------------------------------------------------------
# 4. Post the bundled review
# ---------------------------------------------------------------------------
COMMIT_ID=$(git rev-parse HEAD)

if (( NUM_COMMENTS > 0 )); then
  # Build the full review payload with inline comments
  PAYLOAD=$(jq -n \
    --arg event "$EVENT" \
    --arg body "$SUMMARY" \
    --arg commit_id "$COMMIT_ID" \
    --argjson comments "$(jq '[.inline_comments[] | {
      path: .path,
      line: (.line // 1),
      side: (.side // "RIGHT"),
      body: .body
    }]' "$OUTPUT_FILE")" \
    '{
      event: $event,
      body: $body,
      commit_id: $commit_id,
      comments: $comments
    }')

  echo "Posting review with ${NUM_COMMENTS} inline comments..."
  echo "$PAYLOAD" | retry gh api "repos/${REPO}/pulls/${PR_NUMBER}/reviews" \
    --method POST \
    --input -
else
  # Review without inline comments (pass/skip)
  echo "Posting review (no inline comments)..."
  retry gh api "repos/${REPO}/pulls/${PR_NUMBER}/reviews" \
    --method POST \
    --field event="$EVENT" \
    --field body="$SUMMARY" \
    --field commit_id="$COMMIT_ID"
fi

# ---------------------------------------------------------------------------
# 5. On pass/skip, dismiss any lingering REQUEST_CHANGES reviews
# ---------------------------------------------------------------------------
if (( EXIT_CODE == 0 )); then
  echo "Verdict is pass/skip — running cleanup for any lingering reviews..."
  bash "$(dirname "$0")/cleanup-prior-reviews.sh" 2>/dev/null || true
fi

echo "Review posted. Exit code: ${EXIT_CODE}"
exit "$EXIT_CODE"
